<template><section class="page"><div class="panel"><div class="toolbar"><el-select v-model="form.carrierCode" style="width:140px"><el-option label="MOCK_A" value="MOCK_A"/><el-option label="MOCK_B" value="MOCK_B"/></el-select><el-select v-model="form.scenario" style="width:220px"><el-option v-for="s in scenarios" :key="s" :label="s" :value="s"/></el-select><el-input v-model="form.trackingNo" style="width:180px"/><el-input-number v-model="form.repeatCount" :min="1" :max="10"/><el-button type="primary" :loading="loading" @click="run">执行场景</el-button></div><el-alert v-if="error" :title="error" type="error" show-icon/><pre v-if="result">{{JSON.stringify(result,null,2)}}</pre></div></section></template><script setup lang="ts">import { reactive, ref } from 'vue'; import { http } from '../api/http'; const scenarios=['NORMAL','DUPLICATE_PUSH','OUT_OF_ORDER','MISSING_EVENT','RETURN_AFTER_DELIVERED','UNKNOWN_STATUS','DELIVERY_FAILED_RECOVERY']; const form=reactive({carrierCode:'MOCK_A',scenario:'NORMAL',trackingNo:'A-DEMO-'+Date.now(),repeatCount:2,intervalMillis:0}); const loading=ref(false); const error=ref(''); const result=ref<any>(); async function run(){loading.value=true;error.value='';try{result.value=await http.post('/simulation/run',form)}catch(e:any){error.value=e.message}finally{loading.value=false}}</script>
